// ---- image helpers ----
function pngSize(file) { const b = fs.readFileSync(file); return { w: b.readUInt32BE(16), h: b.readUInt32BE(20) }; }
function imgRun(file, targetW, opts = {}) { const { w, h } = pngSize(file); return new ImageRun({ type: "png", data: fs.readFileSync(file), transformation: { width: targetW, height: Math.round(targetW * h / w) }, altText: { title: opts.t || "figure", description: opts.d || "figure", name: opts.n || "figure" } }); }

// ---- counters / registries ----
let CH = 0; const FIGN = {}, TBLN = {}, LSTN = {}; const FIGURES = [], TABLES = [];
function fig(file, caption, targetW = 460) {
  FIGN[CH] = (FIGN[CH] || 0) + 1; const num = `${CH}.${FIGN[CH]}`; FIGURES.push({ num, cap: caption });
  return [
    new Paragraph({ alignment: AlignmentType.CENTER, spacing: { before: 220, after: 40 }, keepNext: true, children: [imgRun(A(file), Math.round(targetW * 1.38), { t: caption })] }),
    new Paragraph({ alignment: AlignmentType.CENTER, spacing: { after: 220 }, children: [new TextRun({ text: `Figure ${num}: `, bold: true, size: 20, color: GREY }), new TextRun({ text: caption, size: 20, italics: true, color: GREY })] }),
  ];
}
function tblCap(caption) { TBLN[CH] = (TBLN[CH] || 0) + 1; const num = `${CH}.${TBLN[CH]}`; TABLES.push({ num, cap: caption }); return new Paragraph({ alignment: AlignmentType.CENTER, spacing: { before: 140, after: 60 }, keepNext: true, children: [new TextRun({ text: `Table ${num}: `, bold: true, size: 20, color: GREY }), new TextRun({ text: caption, size: 20, italics: true, color: GREY })] }); }
function lstCap(caption) { LSTN[CH] = (LSTN[CH] || 0) + 1; return new Paragraph({ spacing: { before: 120, after: 40 }, keepNext: true, children: [new TextRun({ text: `Listing ${CH}.${LSTN[CH]}: `, bold: true, size: 20, color: GREY }), new TextRun({ text: caption, size: 20, italics: true, color: GREY })] }); }

// ---- text helpers ----
const P = (t, o = {}) => new Paragraph({ alignment: o.align || AlignmentType.JUSTIFIED, spacing: { after: o.after ?? 210, line: 360 }, children: Array.isArray(t) ? t : [new TextRun({ text: t, size: 24 })] });
const run = (t, o = {}) => new TextRun({ text: t, size: o.size || 24, bold: o.bold, italics: o.i, color: o.color, font: o.font });
const formula = (t) => new Paragraph({ alignment: AlignmentType.CENTER, spacing: { before: 60, after: 140 }, children: [new TextRun({ text: t, italics: true, size: 24 })] });
function H1(t) { CH++; FIGN[CH] = 0; TBLN[CH] = 0; LSTN[CH] = 0; return new Paragraph({ heading: HeadingLevel.HEADING_1, pageBreakBefore: true, children: [new TextRun(`Chapter ${CH}    ${t}`)] }); }
const FH1 = (t) => new Paragraph({ heading: HeadingLevel.HEADING_1, pageBreakBefore: true, children: [new TextRun(t)] });
