const NUM = (items) => items.map((it) => new Paragraph({ numbering: { reference: "num", level: 0 }, spacing: { after: 90, line: 336 }, children: Array.isArray(it) ? it : [new TextRun({ text: it, size: 24 })] }));
const leader = (label, page) => new Paragraph({ spacing: { after: 60, line: 264 }, tabStops: [{ type: TabStopType.RIGHT, position: 9026, leader: LeaderType.DOT }], children: [new TextRun({ text: label + "\t" + String(page || ""), size: 22 })] });

// ---- tables ----
const bd = { style: BorderStyle.SINGLE, size: 4, color: "BBBBBB" };
const BORDERS = { top: bd, bottom: bd, left: bd, right: bd, insideHorizontal: bd, insideVertical: bd };
function table(headers, rows, colW) {
  const total = colW.reduce((a, b) => a + b, 0);
  const mk = (text, i, head) => new TableCell({ width: { size: colW[i], type: WidthType.DXA }, borders: BORDERS, shading: { fill: head ? "DCF1E2" : "FFFFFF", type: ShadingType.CLEAR }, margins: { top: 55, bottom: 55, left: 110, right: 110 }, verticalAlign: VerticalAlign.CENTER, children: (Array.isArray(text) ? text : String(text).split("\n")).map((ln) => new Paragraph({ spacing: { after: 0, line: 250 }, children: [new TextRun({ text: ln, size: 20, bold: head, color: head ? DGREEN : INK })] })) });
  return new Table({ width: { size: total, type: WidthType.DXA }, columnWidths: colW, rows: [new TableRow({ tableHeader: true, children: headers.map((h, i) => mk(h, i, true)) }), ...rows.map((r) => new TableRow({ children: r.map((c, i) => mk(c, i, false)) }))] });
}
// two-column spec table (use cases, requirements)
function spec(rows, w1 = 2400) { const w2 = 9026 - w1; return table(["Field", "Detail"], rows, [w1, w2]); }
// code listing (single shaded cell, monospace)
function code(lines) {
  const paras = lines.map((l) => new Paragraph({ spacing: { after: 0, line: 236 }, children: [new TextRun({ text: l.length ? l : " ", font: "Consolas", size: 17, color: "111111" })] }));
  return new Table({ width: { size: 9026, type: WidthType.DXA }, columnWidths: [9026], rows: [new TableRow({ children: [new TableCell({ width: { size: 9026, type: WidthType.DXA }, borders: BORDERS, shading: { fill: CODEBG, type: ShadingType.CLEAR }, margins: { top: 120, bottom: 120, left: 160, right: 120 }, children: paras })] })] });
}
const listing = (caption, lines) => [lstCap(caption), code(lines)];
// plain (unregistered) caption for appendix/manual figures and tables
const pcap = (t) => new Paragraph({ alignment: AlignmentType.CENTER, spacing: { before: 120, after: 60 }, children: [new TextRun({ text: t, size: 20, italics: true, color: GREY })] });

